div.script:
                    //
/* ═══════════════════════════════════════════════════════════════════
   ESS UNIFIED TAB MANAGER
   personal / experience / certification all live on ONE page.
   Tab switching = JS show/hide only. No page navigation. No data loss.
   Bank Details and Org Chart are still separate pages (links).
   ═══════════════════════════════════════════════════════════════════ */
(function() {
'use strict';

var EXP_KEY  = 'ess_exp_staging';
var CERT_KEY = 'ess_cert_pending';

/* ── Switch visible tab ── */
function essShowTab(tabName) {
    /* Show/hide content panels */
    document.querySelectorAll('.ess-tab-panel').forEach(function(panel) {
        panel.style.display = panel.getAttribute('data-ess-panel') === tabName ? '' : 'none';
    });
    /* Update nav button active state */
    document.querySelectorAll('.ess-tab-btn').forEach(function(btn) {
        var active = btn.getAttribute('data-ess-tab') === tabName;
        btn.classList.toggle('active', active);
        btn.classList.toggle('fw-bold', active);
    });
    /* Store active tab in URL hash without reload */
    try { history.replaceState(null, '', '#' + tabName); } catch(e) {}
    /* Notify tab-specific JS */
    document.dispatchEvent(new CustomEvent('ess-tab-activated', {detail: {tab: tabName}}));
}

/* ── Pending state detection ── */
function essPending() {
    var exp = null, cert = null, personal = null;
    try {
        var e = localStorage.getItem(EXP_KEY);  if (e) exp = JSON.parse(e);
        var c = localStorage.getItem(CERT_KEY); if (c) cert = JSON.parse(c);
        var d = localStorage.getItem('profileDraft');
        var a = localStorage.getItem('profileEditActive');
        if (d && a === '1') personal = JSON.parse(d);
    } catch(ex) {}
    return {
        hasPersonal: !!(personal && Object.keys(personal).length > 0),
        hasExp:  !!(exp  && exp.changes  && exp.changes.length  > 0),
        hasCert: !!(cert && cert.changes && cert.changes.length > 0),
    };
}

function essUpdateBar() {
    var bar    = document.getElementById('ess-global-bar');
    var spacer = document.getElementById('ess-bar-spacer');
    var sumEl  = document.getElementById('ess-bar-summary');
    var disc   = document.getElementById('ess-global-disc');
    var btn    = document.getElementById('ess-submit-all-btn');
    if (!bar) return;
    var p     = essPending();
    var parts = [];
    if (p.hasPersonal) parts.push('<strong>Personal Details</strong>');
    if (p.hasExp)      parts.push('<strong>Experience &amp; Skills</strong>');
    if (p.hasCert)     parts.push('<strong>Certifications</strong>');
    if (parts.length > 0) {
        if (sumEl) sumEl.innerHTML = parts.join(', ');
        bar.style.display = 'block';
        if (spacer) spacer.style.height = '120px';
        if (btn && disc) { btn.disabled = !disc.checked; btn.style.opacity = disc.checked ? '1' : '0.6'; }
    } else {
        bar.style.display = 'none';
        if (spacer) spacer.style.height = '0';
        if (sumEl) sumEl.innerHTML = '';
        if (disc) disc.checked = false;
        if (btn) { btn.disabled = true; btn.style.opacity = '0.6'; }
    }
}

function essSubmitPersonal(csrf) {
    try {
        var d = localStorage.getItem('profileDraft');
        var a = localStorage.getItem('profileEditActive');
        if (!d || a !== '1') return Promise.resolve();
        var fields = JSON.parse(d);
        if (!fields || !Object.keys(fields).length) return Promise.resolve();
        var fd = new FormData();
        fd.append('csrf_token', csrf);
        Object.keys(fields).forEach(function(k){ fd.append(k, fields[k]); });
        return fetch('/my/employee/personal', {method:'POST', body:fd})
            .then(function(r){ return r.json(); })
            .then(function(d2){
                if (d2.success) {
                    localStorage.removeItem('profileDraft');
                    localStorage.removeItem('profileEditActive');
                }
                return d2;
            });
    } catch(e) { return Promise.resolve(); }
}

function essSubmitExp(csrf) {
    var exp = null;
    try { var e = localStorage.getItem(EXP_KEY); if (e) exp = JSON.parse(e); } catch(ex) {}
    if (!exp || !exp.changes || !exp.changes.length) return Promise.resolve();
    var changes = exp.changes; var errors = [];
    function next(i) {
        if (i >= changes.length) {
            if (errors.length) return Promise.reject(new Error(errors.join('; ')));
            try { localStorage.removeItem(EXP_KEY); } catch(e) {}
            return Promise.resolve();
        }
        var c = changes[i]; var fd = new FormData(); fd.append('csrf_token', csrf);
        if (c.type === 'add_batch') {
            fd.append('action','add_skill'); fd.append('batch_skills', JSON.stringify(c.payload.batch_skills));
        } else if (c.type === 'edit') {
            fd.append('action','edit_skill'); fd.append('skill_record_id',c.rowId);
            fd.append('level_id',c.payload.level_id); fd.append('level_name',c.payload.level_name);
        } else if (c.type === 'delete') {
            fd.append('action','delete_skill'); fd.append('skill_record_id',c.rowId);
        } else { return next(i+1); }
        return fetch('/my/employee/experience',{method:'POST',body:fd})
            .then(function(r){return r.json();})
            .then(function(d){if(!d.success)errors.push(d.error||'failed');return next(i+1);})
            .catch(function(){errors.push('network');return next(i+1);});
    }
    return next(0);
}

function essSubmitCert(csrf) {
    var cert = null;
    try { var c = localStorage.getItem(CERT_KEY); if (c) cert = JSON.parse(c); } catch(ex) {}
    if (!cert || !cert.changes || !cert.changes.length) return Promise.resolve();
    var changes = cert.changes; var errors = [];
    function next(i) {
        if (i >= changes.length) {
            if (errors.length) return Promise.reject(new Error(errors.join('; ')));
            try { localStorage.removeItem(CERT_KEY); } catch(e) {}
            return Promise.resolve();
        }
        var c = changes[i]; var fd = new FormData(); fd.append('csrf_token', csrf);
        if (c.type === 'delete') {
            fd.append('action','delete_certification'); fd.append('skill_record_id',c.rowId);
        } else if (c.type === 'add' && c.payload) {
            fd.append('action','add_certification'); fd.append('skill_id',c.payload.skillId||'');
            fd.append('valid_from',c.payload.validFrom||''); fd.append('valid_to',c.payload.validTo||'');
        } else if (c.type === 'edit' && c.payload) {
            fd.append('action','edit_certification'); fd.append('skill_record_id',c.rowId);
            fd.append('valid_from',c.payload.validFrom||''); fd.append('valid_to',c.payload.validTo||'');
        } else { return next(i+1); }
        return fetch('/my/employee/certification',{method:'POST',body:fd})
            .then(function(r){return r.json();})
            .then(function(d){if(!d.success)errors.push(d.error||'failed');return next(i+1);})
            .catch(function(){errors.push('network');return next(i+1);});
    }
    return next(0);
}

document.addEventListener('DOMContentLoaded', function() {

    /* Intercept portal nav clicks — save staged data before navigating */
    document.querySelectorAll('.ess-portal-nav').forEach(function(link) {
        link.addEventListener('click', function(e) {
            e.preventDefault();
            var dest = this.getAttribute('href');
            try {
                if (typeof window.essSaveBeforeNav === 'function') {
                    window.essSaveBeforeNav();
                }
            } catch(err) {}
            window.location.href = dest;
        });
    });

    /* Global bar init */
    essUpdateBar();
    setInterval(essUpdateBar, 2000);

    /* Disclaimer gates submit */
    var disc = document.getElementById('ess-global-disc');
    var btn  = document.getElementById('ess-submit-all-btn');
    if (disc) disc.addEventListener('change', function() {
        if (btn) { btn.disabled = !this.checked; btn.style.opacity = this.checked ? '1' : '0.6'; }
    });

    /* Discard all */
    var discardBtn = document.getElementById('ess-discard-btn');
    if (discardBtn) discardBtn.addEventListener('click', function() {
        if (!confirm('Discard ALL pending changes across all tabs?')) return;
        try { localStorage.removeItem(EXP_KEY); localStorage.removeItem(CERT_KEY);
              localStorage.removeItem('profileDraft'); localStorage.removeItem('profileEditActive'); } catch(e) {}
        essUpdateBar();
        /* Reload to reset in-memory staged state */
        location.href = '/my/employee/personal';
    });

    /* Submit All */
    if (btn) btn.addEventListener('click', function() {
        if (!disc || !disc.checked) return;
        var csrf = '';
        var csrfEl = document.querySelector('input[name="csrf_token"]');
        if (csrfEl) csrf = csrfEl.value;

        btn.disabled = true;
        btn.innerHTML = '<i class="fa fa-spinner fa-spin me-1"></i>Submitting...';
        if (discardBtn) discardBtn.disabled = true;
        if (disc) disc.disabled = true;

        var errors = [];
        essSubmitPersonal(csrf)
            .catch(function(e){ errors.push('Personal: ' + (e.message||'failed')); })
            .then(function(){ return essSubmitExp(csrf); })
            .catch(function(e){ errors.push('Experience: ' + (e.message||'failed')); })
            .then(function(){ return essSubmitCert(csrf); })
            .catch(function(e){ errors.push('Certifications: ' + (e.message||'failed')); })
            .then(function(){
                if (errors.length > 0) {
                    alert('Some submissions failed:
' + errors.join('
'));
                    btn.disabled = false;
                    btn.innerHTML = '<i class="fa fa-paper-plane me-1"></i>Submit All for HR Approval';
                    if (discardBtn) discardBtn.disabled = false;
                    if (disc) disc.disabled = false;
                } else {
                    var overlay = document.createElement('div');
                    overlay.style.cssText = 'position:fixed;inset:0;z-index:99999;background:rgba(255,255,255,0.97);display:flex;align-items:center;justify-content:center;';
                    overlay.innerHTML = '<div style="text-align:center;padding:40px;background:#fff;border-radius:16px;box-shadow:0 8px 40px rgba(0,0,0,0.14);max-width:440px;width:90%;">' +
                        '<div style="font-size:56px;margin-bottom:16px;">&#x2705;</div>' +
                        '<h4 style="color:#155724;font-weight:700;margin-bottom:12px;">All Changes Submitted!</h4>' +
                        '<p style="color:#555;">Your changes have been sent to HR for approval.</p>' +
                        '<p style="color:#888;font-size:13px;margin-top:12px;"><i class="fa fa-refresh fa-spin me-1"></i>Reloading...</p>' +
                        '</div>';
                    document.body.appendChild(overlay);
                    setTimeout(function(){ location.href = '/my/employee/personal'; }, 1500);
                }
            });
    });

    /* Photo upload */
    var photoInput = document.getElementById('photoUploadInput');
    if (photoInput) {
        photoInput.addEventListener('change', function() {
            if (!this.files || !this.files[0]) return;
            var file = this.files[0];
            var statusEl = document.getElementById('photoUploadStatus');
            var imgEl    = document.getElementById('employeePhotoImg');
            if (file.size > 5*1024*1024) {
                statusEl.innerHTML = '<span class="text-danger">File too large. Max 5MB.</span>'; return;
            }
            statusEl.innerHTML = '<span class="text-muted"><i class="fa fa-spinner fa-spin me-1"></i>Uploading...</span>';
            var fd = new FormData(); fd.append('photo', file);
            fetch('/my/employee/upload-photo', {method:'POST', body:fd})
                .then(function(r){ return r.json(); })
                .then(function(data){
                    if (data.success) {
                        imgEl.src = data.image_url + '?t=' + Date.now();
                        imgEl.classList.remove('opacity-50');
                        statusEl.innerHTML = '<span style="color:#2C5832;"><i class="fa fa-check me-1"></i>Photo updated!</span>';
                        setTimeout(function(){ statusEl.innerHTML=''; }, 3000);
                    } else {
                        statusEl.innerHTML = '<span class="text-danger">'+(data.error||'Upload failed')+'</span>';
                    }
                }).catch(function(){ statusEl.innerHTML='<span class="text-danger">Upload failed.</span>'; });
        });
    }

});

window.essShowTab    = essShowTab;
window.essUpdateBar  = essUpdateBar;

})();
//
